import { useState, useCallback, useRef } from "react";

const BRASAO = "data:image/png;base64,";

// Lei Municipal nº 3.271/2026 — Anexo Único (Diário Oficial Edição 2082, 24/02/2026)
const SCORING_RULES = [
    { key: "mulher", pts: 3, label: "Mulher responsável pela família (CadÚnico)", keywords: ["mulher na condição de responsável", "mulher responsável"] },
    { key: "negro", pts: 1, label: "Pessoa negra na composição familiar (CadÚnico)", keywords: ["pessoa negra"] },
    { key: "deficiencia", pts: 3, label: "Pessoa com deficiência na família", keywords: ["deficiência", "deficiencia"] },
    { key: "idoso", pts: 2, label: "Idoso na composição familiar", keywords: ["idoso"] },
    { key: "crianca", pts: 1, label: "Criança ou adolescente na família", keywords: ["criança ou adolescente", "criança", "adolescente"] },
    { key: "cancer", pts: 2, label: "Câncer ou doença rara crônica/degenerativa", keywords: ["câncer", "doença rara", "cancer"] },
    { key: "violencia", pts: 2, label: "Vítima de violência doméstica (Lei Maria da Penha)", keywords: ["violência doméstica", "violencia domestica", "maria da penha"] },
    { key: "indigena", pts: 1, label: "Povos indígenas e quilombolas (CadÚnico)", keywords: ["indígena", "quilombola", "povos indígenas", "integrantes de povos"] },
    { key: "risco", pts: 3, label: "Residente em área de risco (PMRR/CPRM/Defesa Civil)", keywords: ["área de risco", "deslizamento", "inundação", "pmrr", "cprm", "defesa civil"] },
    { key: "distrato", pts: 1, label: "Distrato ou rescisão involuntária de contrato", keywords: ["distratado", "rescindido involuntariamente", "reincidido involuntariamente"] },
    { key: "precaria", pts: 2, label: "Habitação precária (sem alvenaria/madeira aparelhada)", keywords: ["habitação precária", "parede", "alvenaria"] },
    { key: "coabitacao", pts: 1, label: "Coabitação familiar (domicílio exclusivo)", keywords: ["coabitação", "coabitacao"] },
    { key: "adensamento", pts: 2, label: "Adensamento excessivo em domicílio alugado", keywords: ["adensamento excessivo"] },
    { key: "onus_aluguel", pts: 2, label: "Ônus excessivo com aluguel (>30% da renda)", keywords: ["ônus excessivo", "onus excessivo"] },
    { key: "aluguel_social", pts: 2, label: "Aluguel social provisório", keywords: ["aluguel social provisório", "aluguel social"] },
    { key: "situacao_rua", pts: 2, label: "Situação de rua ou trajetória de rua", keywords: ["situação de rua", "situacao de rua", "trajetória de rua"] },
];

function scoreCriterios(texto) {
    const t = (texto || "").toLowerCase();
    return SCORING_RULES.filter(r => r.keywords.some(k => t.includes(k)));
}
function checkEligibility(row) {
    const obs = (row["Conteúdo"] || "").toLowerCase();
    if (obs.includes("teste") || obs.includes("não se aplica")) return { ok: false, reason: "Cadastro de TESTE" };
    const renda = (row["assunto.renda_fami_1h7e2u1h"] || "").toLowerCase();
    if (renda.includes("acima de 5") || renda.includes("4 a 5") || renda.includes("3 a 4")) return { ok: false, reason: "Renda acima da Faixa I (> R$ 2.850)" };
    const tempo = (row["assunto.tempo_de_r_1hxctn1h"] || "").toLowerCase();
    if (tempo.includes("2 anos") || tempo.includes("1 ano")) return { ok: false, reason: "Tempo de residência insuficiente (< 5 anos)" };
    return { ok: true, reason: "" };
}
function parseCSV(text) {
    const lines = text.split("\n").filter(l => l.trim());
    if (lines.length < 2) return [];
    const headers = lines[0].split(";").map(h => h.replace(/^"|"$/g, "").trim());
    const rows = [];
    for (let i = 1; i < lines.length; i++) {
        const vals = []; let cur = "", inQ = false;
        for (const ch of lines[i]) {
            if (ch === '"') { inQ = !inQ; }
            else if (ch === ";" && !inQ) { vals.push(cur.trim()); cur = ""; }
            else cur += ch;
        }
        vals.push(cur.trim());
        if (vals.length < 3) continue;
        const row = {};
        headers.forEach((h, idx) => { row[h] = (vals[idx] || "").replace(/^"|"$/g, ""); });
        rows.push(row);
    }
    return rows;
}
function processRows(rows) {
    const classified = [], excluded = [];
    for (const row of rows) {
        const { ok, reason } = checkEligibility(row);
        const nome = row["assunto.nome_compl_1hhomv1h"] || row["Nome"] || "—";
        const numero = row["Número"] || "—";
        if (!ok) { excluded.push({ numero, nome, reason }); continue; }
        const criterios = scoreCriterios(row["assunto.preencha_o_1hwv1v1h"] || "");
        const total = criterios.reduce((s, c) => s + c.pts, 0);
        classified.push({
            numero, nome, total, criterios,
            cpf: row["assunto.cpf_n_do_r_1hyks41h"] || "—",
            rg: row["assunto.rg_do_resp_1hs6871h"] || "—",
            telefone: row["assunto.telefones__1huvhq1h"] || "—",
            nasc: row["Data de Nascimento"] || "—",
            cadUnico: row["assunto.possui_cad_1h6y6o1h"] || "—",
            renda: row["assunto.renda_fami_1h7e2u1h"] || "Não informada",
            tempo: row["assunto.tempo_de_r_1hxctn1h"] || "Não informado",
            estadoCivil: row["assunto.estado_civ_1hpruu1h"] || "—",
        });
    }
    classified.sort((a, b) => b.total - a.total || (a.nome < b.nome ? -1 : 1));
    classified.forEach((c, i) => { c.posicao = i + 1; });
    return { classified, excluded };
}
const C = { azul: "#1A3A5C", azulM: "#2E75B6", azulL: "#D6E4F0", ouro: "#C8893A", bg: "#EEF2F7", card: "#FFFFFF", text: "#1C2B3A", muted: "#64748B", border: "#CBD5E1", verde: "#166534", verdeL: "#DCFCE7", vermelho: "#991B1B", vermelhoL: "#FEE2E2", amarelo: "#92400E" };
const Badge = ({ color, bg, children }) => <span style={{ background: bg, color, borderRadius: 12, padding: "2px 10px", fontSize: 11, fontWeight: 600, whiteSpace: "nowrap" }}>{children}</span>;
const Medal = ({ pos }) => { const bg = pos === 1 ? "#C8893A" : pos === 2 ? "#94A3B8" : pos === 3 ? "#CD7F32" : C.azulM; return <div style={{ width: 32, height: 32, borderRadius: "50%", background: bg, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 700, fontSize: 13, flexShrink: 0, boxShadow: "0 2px 6px rgba(0,0,0,.2)" }}>{pos}°</div>; };
const HBar = ({ title, data, maxVisible = 8 }) => {
    const [expanded, setExpanded] = useState(false);
    const max = Math.max(...data.map(d => d.value), 1);
    const cols = ["#2E75B6", "#166534", "#C8893A", "#991B1B", "#6366F1", "#0891B2", "#D97706", "#065F46"];
    const visible = expanded ? data : data.slice(0, maxVisible);
    const hasMore = data.length > maxVisible;
    const renderBar = (d, i) => (
        <div key={i} style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ width: 145, fontSize: 11, color: C.muted, textAlign: "right", flexShrink: 0, lineHeight: 1.3 }}>{d.label}</div>
            <div style={{ flex: 1, background: "#F1F5F9", borderRadius: 6, overflow: "hidden", height: 28 }}>
                <div style={{ width: (d.value / max * 100) + "%", height: "100%", background: cols[i % cols.length], borderRadius: 6, display: "flex", alignItems: "center", justifyContent: "flex-end", paddingRight: 8, minWidth: d.value > 0 ? 28 : 0, transition: "width .6s ease" }}>
                    {d.value > 0 && <span style={{ color: "#fff", fontSize: 11, fontWeight: 700 }}>{d.value}</span>}
                </div>
            </div>
        </div>
    );
    return (
        <div style={{ background: C.card, borderRadius: 12, padding: "20px 24px", boxShadow: "0 1px 8px rgba(0,0,0,.07)" }}>
            <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 15, fontWeight: 700, color: C.azul, marginBottom: 18 }}>{title}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                {visible.map((d, i) => renderBar(d, i))}
            </div>
            {hasMore && (
                <button onClick={() => setExpanded(!expanded)}
                    style={{ marginTop: 14, width: "100%", background: "none", border: "1px solid " + C.border, borderRadius: 8, padding: "7px 0", fontSize: 12, fontWeight: 600, color: C.azulM, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
                    {expanded ? "▲ Recolher" : "▼ Ver mais " + (data.length - maxVisible) + " registros"}
                </button>
            )}
        </div>
    );
};
const LineChart = ({ title, data }) => { if (!data.length) return null; const max = Math.max(...data.map(d => d.value), 1); const W = 400, H = 160, pad = { t: 10, r: 10, b: 30, l: 30 }; const cW = W - pad.l - pad.r, cH = H - pad.t - pad.b; const pts = data.map((d, i) => ({ x: pad.l + (i / Math.max(data.length - 1, 1)) * cW, y: pad.t + (1 - d.value / max) * cH, ...d })); const path = pts.map((p, i) => `${i === 0 ? "M" : "L"}${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(" "); const area = `${path} L${pts[pts.length - 1].x},${pad.t + cH} L${pts[0].x},${pad.t + cH} Z`; return (<div style={{ background: C.card, borderRadius: 12, padding: "20px 24px", boxShadow: "0 1px 8px rgba(0,0,0,.07)" }}><div style={{ fontFamily: "'Playfair Display',serif", fontSize: 15, fontWeight: 700, color: C.azul, marginBottom: 12 }}>{title}</div><svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto" }}><defs><linearGradient id="lg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={C.azulM} stopOpacity="0.3" /><stop offset="100%" stopColor={C.azulM} stopOpacity="0.02" /></linearGradient></defs><path d={area} fill="url(#lg)" /><path d={path} fill="none" stroke={C.azulM} strokeWidth="2.5" strokeLinejoin="round" />{pts.map((p, i) => (<g key={i}><circle cx={p.x} cy={p.y} r={4} fill={C.azulM} stroke="#fff" strokeWidth={1.5} />{i % Math.ceil(pts.length / 8) === 0 && <text x={p.x} y={H - 6} textAnchor="middle" fontSize={8} fill={C.muted}>{p.label}</text>}</g>))}{[0, .5, 1].map((f, i) => <text key={i} x={pad.l - 4} y={pad.t + (1 - f) * cH + 4} textAnchor="end" fontSize={8} fill={C.muted}>{Math.round(max * f)}</text>)}</svg></div>); };

async function generatePDF({ classified, excluded, filename }) {
    const top180 = classified.slice(0, 180);
    const now = new Date().toLocaleString("pt-BR");
    
    // Carregar imagem do brasão e converter para base64
    let brasaoBase64 = "";
    try {
        const response = await fetch("/brasao_boituva.png.png");
        const blob = await response.blob();
        brasaoBase64 = await new Promise((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result);
            reader.readAsDataURL(blob);
        });
    } catch (e) {
        console.error("Erro ao carregar brasão:", e);
    }
    
    const dataRows = top180.map((c, i) => {
        const tags = c.criterios.map(cr => `<span style="display:inline-block;background:#D6E4F0;color:#1A3A5C;border-radius:4px;padding:1px 6px;font-size:8px;margin:1px;">${cr.label} (+${cr.pts})</span>`).join(" ");
        const shade = i % 2 === 0 ? "#F8FAFC" : "#FFFFFF";
        const al = c.tempo.includes("4 anos") ? ` <span style="color:#92400E;font-weight:700">⚠</span>` : "";
        return `<tr style="background:${shade}"><td style="padding:4px 6px;text-align:center;font-weight:700;color:${i < 3 ? "#C8893A" : "#1A3A5C"}">${i + 1}°</td><td style="padding:4px 6px;font-weight:600">${c.nome}</td><td style="padding:4px 6px;font-size:9px;color:#64748B">${c.numero}</td><td style="padding:4px 6px;font-size:9px">${c.cadUnico}</td><td style="padding:4px 6px;font-size:9px">${c.tempo.replace(/["[\]]/g, "")}${al}</td><td style="padding:4px 6px;font-size:9px">${c.renda.replace(/["[\]]/g, "").substring(0, 45)}</td><td style="padding:4px 6px;text-align:center;font-weight:700;color:#1A3A5C;font-size:13px">${c.total}</td><td style="padding:4px 6px;font-size:8px">${tags}</td></tr>`;
    }).join("");
    const exclRows = excluded.map(e => `<tr><td style="padding:3px 6px;font-size:9px">${e.numero}</td><td style="padding:3px 6px;font-size:9px">${e.nome}</td><td style="padding:3px 6px;font-size:9px;color:#991B1B">${e.reason}</td></tr>`).join("");
    const tblPts = SCORING_RULES.map(r => `<tr><td style="padding:3px 8px;font-size:9px;border-bottom:1px solid #E2E8F0">${r.label}</td><td style="padding:3px 8px;font-size:9px;text-align:center;font-weight:700;color:#1A3A5C;border-bottom:1px solid #E2E8F0">${r.pts}</td></tr>`).join("");
    
    const imgTag = brasaoBase64 ? `<div style="width:70px;height:70px;background:#1A3A5C;border-radius:4px;overflow:hidden;display:flex;align-items:center;justify-content:center;"><img src="${brasaoBase64}" style="width:100%;height:100%;object-fit:contain;"/></div>` : "";
    
    const html = `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;font-size:10px;color:#1C2B3A}.hdr{display:flex;align-items:center;gap:16px;padding:16px 24px;background:#1A3A5C;color:#fff}.hdr h1{font-size:18px;font-weight:700;margin-bottom:3px}.hdr p{font-size:10px;opacity:.8;margin-top:2px}.sec{padding:12px 24px}.st{font-size:14px;font-weight:700;color:#1A3A5C;border-bottom:2px solid #1A3A5C;padding-bottom:4px;margin-bottom:10px}table{width:100%;border-collapse:collapse}th{background:#1A3A5C;color:#fff;padding:5px 6px;text-align:left;font-size:9px;font-weight:600}td{border-bottom:1px solid #E2E8F0;vertical-align:top}.ft{padding:10px 24px;text-align:center;font-size:8px;color:#64748B;border-top:1px solid #CBD5E1;margin-top:16px}@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head><body><div class="hdr">${imgTag}<div><h1>PREFEITURA MUNICIPAL DE BOITUVA</h1><p>Secretaria Municipal de Planejamento Urbano e Habitação</p><p>Programa MCMV — FAR | ESLE JOSÉ COSTA I</p><p style="margin-top:5px;background:rgba(255,255,255,.15);display:inline-block;padding:2px 10px;border-radius:4px;">⚖️ Lei nº 3.271/2026 | Portaria MCID nº 738/2024</p><p style="margin-top:4px;opacity:.65">Relatório: ${now} | ${filename}</p></div></div><div class="sec"><div class="st">CLASSIFICAÇÃO HABITACIONAL — Anexo Único da Lei nº 3.271/2026</div><p style="margin-bottom:10px;font-size:9px;color:#64748B">Diário Oficial de Boituva — Edição 2082, 24/02/2026. Desempate (Art.12): maior idade › nº dependentes › tempo residência.</p><table><thead><tr><th style="width:30px">Pos.</th><th style="width:160px">Nome</th><th style="width:80px">Protocolo</th><th style="width:55px">CadÚnico</th><th style="width:70px">Residência</th><th style="width:100px">Renda</th><th style="width:35px;text-align:center">Pts</th><th>Critérios</th></tr></thead><tbody>${dataRows}</tbody></table></div>${excluded.length > 0 ? `<div class="sec" style="margin-top:16px"><div class="st">CANDIDATOS EXCLUÍDOS (${excluded.length})</div><table><thead><tr><th>Protocolo</th><th>Nome</th><th>Motivo</th></tr></thead><tbody>${exclRows}</tbody></table></div>` : ""}<div class="sec" style="margin-top:16px"><div class="st">TABELA DE PONTUAÇÃO — ANEXO ÚNICO (Lei nº 3.271/2026)</div><table style="width:55%"><thead><tr><th>Critério</th><th style="width:80px;text-align:center">Pts</th></tr></thead><tbody>${tblPts}</tbody></table></div><div class="ft">Lei nº 3.271/2026 | Portaria MCID nº 738/2024 | Lei nº 14.620/2023 | LGPD (Lei nº 13.709/2018)<br/>Uso interno — sigiloso conforme LGPD.</div></body></html>`;
    const blob = new Blob([html], { type: "text/html;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const w = window.open(url, "_blank");
    if (w) setTimeout(() => w.print(), 800);
}

export default function App() {
    const [state, setState] = useState("idle");
    const [classified, setClassified] = useState([]);
    const [excluded, setExcluded] = useState([]);
    const [filename, setFilename] = useState("");
    const [page, setPage] = useState(1);
    const [search, setSearch] = useState("");
    const PER_PAGE = 20;
    const fileRef = useRef();

    const handleFile = useCallback((file) => {
        if (!file) return;
        setFilename(file.name); setState("loading");
        const reader = new FileReader();
        reader.onload = (e) => {
            const rows = parseCSV(e.target.result);
            const result = processRows(rows);
            setClassified(result.classified); setExcluded(result.excluded);
            setState("done"); setPage(1); setSearch("");
        };
        reader.readAsText(file, "UTF-8");
    }, []);

    const onDrop = useCallback((e) => { e.preventDefault(); const f = e.dataTransfer.files[0]; if (f?.name.endsWith(".csv")) handleFile(f); }, [handleFile]);

    const filtered = classified.filter(c => !search || c.nome.toLowerCase().includes(search.toLowerCase()) || c.numero.includes(search));
    const top180 = filtered.slice(0, 180);
    const paginated = top180.slice((page - 1) * PER_PAGE, page * PER_PAGE);
    const totalPages = Math.ceil(top180.length / PER_PAGE);

    const rendaCount = {};
    classified.forEach(c => { let k = c.renda.replace(/["[\]]/g, "").trim(); if (k.includes("2.850") || k.includes("2 sal")) k = "Até R$ 2.850 (Faixa I)"; else if (!k || k === "Não informada") k = "Não informada"; else k = k.substring(0, 32); rendaCount[k] = (rendaCount[k] || 0) + 1; });
    const rendaData = Object.entries(rendaCount).sort((a, b) => b[1] - a[1]).map(([label, value]) => ({ label, value }));
    const critCount = {};
    classified.forEach(c => c.criterios.forEach(cr => { critCount[cr.label] = (critCount[cr.label] || 0) + 1; }));
    const critData = Object.entries(critCount).sort((a, b) => b[1] - a[1]).slice(0, 8).map(([label, value]) => ({ label: label.substring(0, 30), value }));
    const pontData = classified.slice(0, 30).map((c, i) => ({ label: (i + 1) + "°", value: c.total }));
    const tempoCount = {};
    classified.forEach(c => { const k = c.tempo.replace(/["[\]]/g, "").trim() || "Não informado"; tempoCount[k] = (tempoCount[k] || 0) + 1; });
    const tempoData = Object.entries(tempoCount).sort((a, b) => b[1] - a[1]).map(([label, value]) => ({ label, value }));
    const comCad = classified.filter(c => c.cadUnico.toLowerCase() === "sim").length;
    const avgPts = classified.length ? (classified.reduce((s, c) => s + c.total, 0) / classified.length).toFixed(1) : 0;

    return (
        <div style={{ minHeight: "100vh", background: C.bg, fontFamily: "'Source Sans 3',sans-serif" }}>
            <div style={{ background: C.azul, color: "#fff", padding: "0 32px", display: "flex", alignItems: "center", gap: 20, height: 72, boxShadow: "0 4px 20px rgba(0,0,0,.25)" }}>
                <div style={{ width: 52, height: 52, background: "#1A3A5C", borderRadius: 4, overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                    <img src="/brasao_boituva.png.png" alt="Brasão Boituva" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
                </div>
                <div>
                    <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 18, fontWeight: 700 }}>Prefeitura Municipal de Boituva</div>
                    <div style={{ fontSize: 11, opacity: .75, marginTop: 1 }}>Sistema de Classificação Habitacional — MCMV/FAR | Lei nº 3.271/2026</div>
                </div>
                <div style={{ marginLeft: "auto", fontSize: 11, opacity: .6, textAlign: "right" }}>Secretaria de Planejamento<br />Urbano e Habitação</div>
            </div>
            <div style={{ maxWidth: 1280, margin: "0 auto", padding: "28px 24px" }}>

                {state === "idle" && (
                    <div onDrop={onDrop} onDragOver={e => e.preventDefault()} onClick={() => fileRef.current?.click()}
                        style={{ border: "2px dashed " + C.azulM, borderRadius: 16, background: C.card, padding: "60px 40px", textAlign: "center", cursor: "pointer", boxShadow: "0 2px 12px rgba(0,0,0,.06)" }}>
                        <input ref={fileRef} type="file" accept=".csv" style={{ display: "none" }} onChange={e => handleFile(e.target.files[0])} />
                        <div style={{ fontSize: 48, marginBottom: 16 }}>📂</div>
                        <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 22, color: C.azul, fontWeight: 700, marginBottom: 8 }}>Carregar Arquivo CSV</div>
                        <div style={{ color: C.muted, fontSize: 14, maxWidth: 480, margin: "0 auto", lineHeight: 1.6 }}>Arraste e solte o arquivo exportado do sistema 1DOC, ou clique para selecionar.</div>
                        <div style={{ marginTop: 14, display: "inline-block", background: C.azulL, color: C.azul, padding: "6px 18px", borderRadius: 6, fontSize: 12, fontWeight: 600 }}>⚖️ Lei nº 3.271/2026 — Diário Oficial Edição 2082 (24/02/2026)</div>
                        <br />
                        <div style={{ marginTop: 14, display: "inline-block", background: C.azul, color: "#fff", padding: "10px 28px", borderRadius: 8, fontSize: 14, fontWeight: 600 }}>Selecionar Arquivo CSV</div>
                    </div>
                )}

                {state === "loading" && (
                    <div style={{ textAlign: "center", padding: "80px 0" }}>
                        <div style={{ fontSize: 40, marginBottom: 16 }}>⏳</div>
                        <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 20, color: C.azul }}>Processando candidatos...</div>
                    </div>
                )}

                {state === "done" && (<>
                    <div style={{ background: C.card, borderRadius: 10, padding: "12px 20px", display: "flex", alignItems: "center", gap: 12, marginBottom: 20, boxShadow: "0 1px 6px rgba(0,0,0,.06)", borderLeft: "4px solid " + C.azulM }}>
                        <span style={{ fontSize: 20 }}>📄</span>
                        <span style={{ fontSize: 13, color: C.muted }}>Analisando:</span>
                        <span style={{ fontWeight: 700, color: C.azul, fontSize: 13 }}>{filename}</span>
                        <span style={{ marginLeft: 8, fontSize: 11, background: C.azulL, color: C.azul, padding: "2px 10px", borderRadius: 20, fontWeight: 600 }}>⚖️ Lei nº 3.271/2026</span>
                        <span style={{ marginLeft: "auto", background: C.azulL, color: C.azul, borderRadius: 20, padding: "3px 14px", fontSize: 12, fontWeight: 700 }}>{classified.length + excluded.length} registros</span>
                        <button onClick={() => { setState("idle"); setClassified([]); setExcluded([]); }} style={{ background: "#FEE2E2", color: C.vermelho, border: "none", borderRadius: 6, padding: "5px 14px", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>🗑 Limpar</button>
                    </div>

                    <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 20 }}>
                        {[
                            { icon: "🏆", label: "Classificados", value: classified.length, sub: "elegíveis", color: C.azul },
                            { icon: "❌", label: "Excluídos", value: excluded.length, sub: "inelegíveis", color: C.vermelho },
                            { icon: "⭐", label: "Pontuação Média", value: avgPts, sub: "pontos / família", color: C.ouro },
                            { icon: "📋", label: "Com CadÚnico", value: comCad, sub: "de " + classified.length + " elegíveis", color: "#166534" }
                        ].map((k, i) => (
                            <div key={i} style={{ background: C.card, borderRadius: 12, padding: "18px 20px", boxShadow: "0 1px 8px rgba(0,0,0,.07)", borderTop: "3px solid " + k.color }}>
                                <div style={{ fontSize: 26, marginBottom: 6 }}>{k.icon}</div>
                                <div style={{ fontSize: 28, fontWeight: 700, color: k.color, fontFamily: "'Playfair Display',serif" }}>{k.value}</div>
                                <div style={{ fontSize: 12, fontWeight: 600, color: C.text, marginTop: 2 }}>{k.label}</div>
                                <div style={{ fontSize: 11, color: C.muted }}>{k.sub}</div>
                            </div>
                        ))}
                    </div>

                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 24 }}>
                        <HBar title="📊 Perfil de Renda dos Classificados" data={rendaData} />
                        <HBar title="🏷️ Critérios Mais Frequentes (Lei 3.271/2026)" data={critData} />
                        <LineChart title="📈 Pontuação dos Top 30 Classificados" data={pontData} />
                        <HBar title="🏠 Tempo de Residência no Município" data={tempoData} />
                    </div>

                    <div style={{ background: C.card, borderRadius: 12, boxShadow: "0 1px 12px rgba(0,0,0,.08)", overflow: "hidden" }}>
                        <div style={{ background: C.azul, padding: "16px 24px", display: "flex", alignItems: "center", gap: 16 }}>
                            <div>
                                <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 17, color: "#fff", fontWeight: 700 }}>🏅 Top {Math.min(180, classified.length)} Classificados</div>
                                <div style={{ fontSize: 11, color: "rgba(255,255,255,.65)", marginTop: 2 }}>Lei nº 3.271/2026 — maior pontuação primeiro</div>
                            </div>
                            <div style={{ marginLeft: "auto", display: "flex", gap: 10, alignItems: "center" }}>
                                <input value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} placeholder="🔍 Buscar nome ou protocolo..."
                                    style={{ background: "rgba(255,255,255,.15)", border: "1px solid rgba(255,255,255,.3)", borderRadius: 8, padding: "7px 14px", fontSize: 12, color: "#fff", outline: "none", width: 240 }} />
                                <button onClick={async () => await generatePDF({ classified, excluded, filename })}
                                    style={{ background: C.ouro, color: "#fff", border: "none", borderRadius: 8, padding: "8px 18px", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>⬇ Baixar Relatório PDF</button>
                            </div>
                        </div>

                        <div style={{ display: "grid", gridTemplateColumns: "50px 1fr 110px 80px 100px 110px 70px", background: "#F1F5F9", padding: "8px 16px", fontSize: 10, fontWeight: 700, color: C.muted, textTransform: "uppercase", letterSpacing: .5, borderBottom: "1px solid " + C.border }}>
                            <div>Pos</div><div>Nome Completo</div><div>Protocolo</div><div>CadÚnico</div><div>Residência</div><div>Renda</div><div style={{ textAlign: "center" }}>Pontos</div>
                        </div>

                        {paginated.map((c, idx) => {
                            const gi = (page - 1) * PER_PAGE + idx;
                            const al = c.tempo.includes("4 anos") || c.tempo.includes("3 anos");
                            return (
                                <div key={c.numero} style={{ display: "grid", gridTemplateColumns: "50px 1fr 110px 80px 100px 110px 70px", padding: "10px 16px", borderBottom: "1px solid " + C.border, background: gi % 2 === 0 ? "#FAFBFD" : "#fff", alignItems: "center" }}>
                                    <Medal pos={c.posicao} />
                                    <div>
                                        <div style={{ fontWeight: 600, fontSize: 13, color: C.text }}>{c.nome}</div>
                                        <div style={{ display: "flex", flexWrap: "wrap", gap: 3, marginTop: 4 }}>
                                            {c.criterios.map(cr => <span key={cr.key} style={{ background: C.azulL, color: C.azul, borderRadius: 10, padding: "1px 7px", fontSize: 10, fontWeight: 500 }}>{cr.label.substring(0, 26)} (+{cr.pts})</span>)}
                                        </div>
                                    </div>
                                    <div style={{ fontSize: 11, color: C.muted, fontFamily: "monospace" }}>{c.numero}</div>
                                    <div><Badge color={c.cadUnico.toLowerCase() === "sim" ? C.verde : C.vermelho} bg={c.cadUnico.toLowerCase() === "sim" ? C.verdeL : C.vermelhoL}>{c.cadUnico}</Badge></div>
                                    <div style={{ fontSize: 11, color: al ? C.amarelo : C.text, fontWeight: al ? 700 : 400 }}>{al ? "⚠ " : ""}{c.tempo.replace(/["[\]]/g, "").trim()}</div>
                                    <div style={{ fontSize: 10, color: C.muted, lineHeight: 1.3 }}>{c.renda.replace(/["[\]]/g, "").substring(0, 35) || "—"}</div>
                                    <div style={{ textAlign: "center", fontWeight: 700, fontSize: 18, color: c.total > 0 ? C.azul : C.muted, fontFamily: "'Playfair Display',serif" }}>{c.total}</div>
                                </div>
                            );
                        })}

                        <div style={{ padding: "12px 16px", display: "flex", alignItems: "center", justifyContent: "space-between", borderTop: "1px solid " + C.border }}>
                            <div style={{ fontSize: 12, color: C.muted }}>Exibindo {Math.min((page - 1) * PER_PAGE + 1, top180.length)}–{Math.min(page * PER_PAGE, top180.length)} de {top180.length} candidatos</div>
                            <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                                {[...Array(Math.min(totalPages, 20))].map((_, i) => (
                                    <button key={i} onClick={() => setPage(i + 1)} style={{ width: 30, height: 30, borderRadius: 6, border: "1px solid " + C.border, background: page === i + 1 ? C.azul : "transparent", color: page === i + 1 ? "#fff" : C.text, fontSize: 12, fontWeight: 600, cursor: "pointer" }}>{i + 1}</button>
                                ))}
                            </div>
                        </div>
                    </div>

                    {excluded.length > 0 && (
                        <div style={{ marginTop: 20, background: C.card, borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 8px rgba(0,0,0,.07)" }}>
                            <div style={{ background: "#991B1B", padding: "12px 20px" }}>
                                <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 15, color: "#fff", fontWeight: 700 }}>❌ Candidatos Excluídos ({excluded.length})</div>
                            </div>
                            {excluded.map((e, i) => (
                                <div key={i} style={{ display: "grid", gridTemplateColumns: "120px 1fr 1fr", padding: "8px 20px", borderBottom: "1px solid " + C.border, background: i % 2 === 0 ? "#FFF8F8" : "#fff", fontSize: 12 }}>
                                    <div style={{ fontFamily: "monospace", color: C.muted }}>{e.numero}</div>
                                    <div style={{ fontWeight: 600, color: C.text }}>{e.nome}</div>
                                    <div style={{ color: "#991B1B" }}>⛔ {e.reason}</div>
                                </div>
                            ))}
                        </div>
                    )}
                </>)}
            </div>
        </div>
    );
}